{
  "domainModel": {
    "classDiagram": "classDiagram\n    class User {\n        +int userId\n        +string username\n        +string email\n        +string password\n        +string nickname\n        +string avatar\n        +string bio\n        +datetime registerTime\n        +string role\n        +register()\n        +login()\n        +updateProfile()\n    }\n\n    class Author {\n        +int articleCount\n        +publishArticle()\n        +editArticle()\n        +deleteArticle()\n    }\n\n    class Admin {\n        +manageAllArticles()\n        +manageAllComments()\n        +manageUsers()\n    }\n\n    class Article {\n        +int articleId\n        +string title\n        +string content\n        +string summary\n        +datetime publishTime\n        +datetime updateTime\n        +int viewCount\n        +getByCategory()\n        +getByTag()\n        +search()\n    }\n\n    class Comment {\n        +int commentId\n        +string content\n        +datetime commentTime\n        +delete()\n    }\n\n    class Category {\n        +int categoryId\n        +string name\n        +string description\n        +getArticles()\n    }\n\n    class Tag {\n        +int tagId\n        +string name\n        +getArticles()\n    }\n\n    class ArticleTag {\n        +int articleId\n        +int tagId\n    }\n\n    User <|-- Author : extends\n    User <|-- Admin : extends\n    User \"1\" --> \"*\" Article : writes\n    User \"1\" --> \"*\" Comment : creates\n    Article \"1\" --> \"*\" Comment : has\n    Article \"*\" --> \"1\" Category : belongs to\n    Article \"*\" --> \"*\" Tag : tagged with\n    ArticleTag \"*\" --> \"1\" Article : references\n    ArticleTag \"*\" --> \"1\" Tag : references\n    Comment \"*\" --> \"0..1\" Comment : replies to\n    Comment \"*\" --> \"1\" User : created by",
    "relationships": [
      {
        "type": "泛化（继承）",
        "description": "User是基类，Author和Admin继承自User",
        "details": [
          {
            "parent": "User",
            "child": "Author",
            "relationship": "继承",
            "description": "Author继承User的所有属性，并增加发布、编辑、删除文章的能力"
          },
          {
            "parent": "User",
            "child": "Admin",
            "relationship": "继承",
            "description": "Admin继承User的所有属性，并增加管理所有内容和管理用户的能力"
          }
        ]
      },
      {
        "type": "关联关系",
        "description": "类之间的语义关联",
        "details": [
          {
            "from": "User",
            "to": "Article",
            "relationship": "关联",
            "multiplicity": "1对多",
            "description": "一个用户（作者）可以撰写多篇文章，一篇文章属于一个用户（作者）"
          },
          {
            "from": "User",
            "to": "Comment",
            "relationship": "关联",
            "multiplicity": "1对多",
            "description": "一个用户可以发表多条评论，一条评论属于一个用户"
          },
          {
            "from": "Article",
            "to": "Comment",
            "relationship": "关联",
            "multiplicity": "1对多",
            "description": "一篇文章可以有多条评论，一条评论属于一篇文章"
          },
          {
            "from": "Article",
            "to": "Category",
            "relationship": "关联",
            "multiplicity": "多对1",
            "description": "多篇文章可以属于同一个分类，一篇文章只能属于一个分类"
          },
          {
            "from": "Article",
            "to": "Tag",
            "relationship": "关联",
            "multiplicity": "多对多",
            "description": "一篇文章可以有多个标签，一个标签可以标记多篇文章"
          },
          {
            "from": "Comment",
            "to": "Comment",
            "relationship": "自关联",
            "multiplicity": "0..1对多",
            "description": "一条评论可以有多个子回复（嵌套回复），子回复指向父评论"
          }
        ]
      },
      {
        "type": "聚合/组合关系",
        "description": "整体与部分的关系",
        "details": [
          {
            "whole": "Article",
            "part": "ArticleTag",
            "relationship": "组合",
            "multiplicity": "1对多",
            "description": "文章和标签的关联关系由ArticleTag维护，ArticleTag的生命周期依赖于Article"
          },
          {
            "whole": "Tag",
            "part": "ArticleTag",
            "relationship": "组合",
            "multiplicity": "1对多",
            "description": "标签和文章的关联关系由ArticleTag维护，ArticleTag的生命周期也依赖于Tag"
          }
        ]
      },
      {
        "type": "多重性约束总结",
        "description": "所有关联关系的多重性汇总",
        "details": [
          {
            "relationship": "User → Article",
            "multiplicity": "1..* : 0..*",
            "description": "一个用户（作者）至少撰写0篇或多篇文章，一篇文章必须属于一个用户"
          },
          {
            "relationship": "User → Comment",
            "multiplicity": "1..* : 0..*",
            "description": "一个用户可以发表0条或多条评论，一条评论必须属于一个用户"
          },
          {
            "relationship": "Article → Comment",
            "multiplicity": "1 : 0..*",
            "description": "一篇文章可以有0条或多条评论，一条评论必须属于一篇文章"
          },
          {
            "relationship": "Article → Category",
            "multiplicity": "0..* : 1",
            "description": "一个分类可以有0篇或多篇文章，一篇文章必须属于一个分类"
          },
          {
            "relationship": "Article → Tag",
            "multiplicity": "0..* : 0..*",
            "description": "一篇文章可以有0个或多个标签，一个标签可以标记0篇或多篇文章"
          },
          {
            "relationship": "Comment → Comment（自关联）",
            "multiplicity": "0..1 : 0..*",
            "description": "一条评论可以有0条或多条子回复，子回复必须有一个父评论（顶级评论无父评论）"
          }
        ]
      }
    ]
  }
}
